Create a new file `packages/relay/src/base-adapter.ts` containing the `BaseRelayAdapter` abstract class that eliminates ~30 lines of boilerplate per adapter.

The class implements the `RelayAdapter` interface and provides:
- Status initialization (`state: 'disconnected'`, `messageCount: { inbound: 0, outbound: 0 }`, `errorCount: 0`)
- `start(relay)` with idempotency guard (skip if already `'connected'`), status transitions (`starting` -> `connected`), relay ref storage, and error handling that calls `recordError()` then re-throws
- `stop()` with idempotency guard (skip if already `'disconnected'`), status transition to `'stopping'` then `'disconnected'`, and relay ref cleanup in a `finally` block
- `getStatus()` returning a shallow copy (`{ ...this._status }`)
- `trackOutbound()` incrementing `messageCount.outbound`
- `trackInbound()` incrementing `messageCount.inbound`
- `recordError(err)` setting `state: 'error'`, incrementing `errorCount`, setting `lastError` (string from Error or String(err)), setting `lastErrorAt` (ISO string)

Subclasses implement three methods:
- `protected abstract _start(relay: RelayPublisher): Promise<void>` — connect to external service
- `protected abstract _stop(): Promise<void>` — disconnect and drain in-flight messages
- `abstract deliver(subject: string, envelope: RelayEnvelope, context?: AdapterContext): Promise<DeliveryResult>` — deliver message

Full implementation:

```typescript
import type {
  RelayAdapter,
  RelayPublisher,
  AdapterStatus,
  AdapterContext,
  DeliveryResult,
} from './types.js';
import type { RelayEnvelope } from '@dorkos/shared/relay-schemas';

/**
 * Optional abstract base class for relay adapters.
 *
 * Handles boilerplate that every adapter needs: status tracking state machine,
 * start/stop idempotency guards, error recording, and relay ref lifecycle.
 *
 * Subclasses implement `_start()`, `_stop()`, and `deliver()`.
 * Direct `RelayAdapter` implementation remains fully supported.
 *
 * @example
 * ```typescript
 * class MyAdapter extends BaseRelayAdapter {
 *   constructor(id: string, config: MyConfig) {
 *     super(id, 'relay.custom.mine', 'My Adapter');
 *   }
 *
 *   protected async _start(relay: RelayPublisher): Promise<void> {
 *     // Connect to external service
 *   }
 *
 *   protected async _stop(): Promise<void> {
 *     // Disconnect and drain in-flight messages
 *   }
 *
 *   async deliver(subject: string, envelope: RelayEnvelope, context?: AdapterContext): Promise<DeliveryResult> {
 *     this.trackOutbound();
 *     return { success: true };
 *   }
 * }
 * ```
 */
export abstract class BaseRelayAdapter implements RelayAdapter {
  readonly id: string;
  readonly subjectPrefix: string | readonly string[];
  readonly displayName: string;

  /** Reference to the relay publisher, set on start, cleared on stop. */
  protected relay: RelayPublisher | null = null;

  private _status: AdapterStatus = {
    state: 'disconnected',
    messageCount: { inbound: 0, outbound: 0 },
    errorCount: 0,
  };

  constructor(
    id: string,
    subjectPrefix: string | readonly string[],
    displayName: string,
  ) {
    this.id = id;
    this.subjectPrefix = subjectPrefix;
    this.displayName = displayName;
  }

  async start(relay: RelayPublisher): Promise<void> {
    if (this._status.state === 'connected') return;
    this._status = { ...this._status, state: 'starting' };
    this.relay = relay;
    try {
      await this._start(relay);
      this._status = {
        ...this._status,
        state: 'connected',
        startedAt: new Date().toISOString(),
      };
    } catch (err) {
      this.recordError(err);
      this.relay = null;
      throw err;
    }
  }

  async stop(): Promise<void> {
    if (this._status.state === 'disconnected') return;
    this._status = { ...this._status, state: 'stopping' };
    try {
      await this._stop();
    } finally {
      this.relay = null;
      this._status = { ...this._status, state: 'disconnected' };
    }
  }

  getStatus(): AdapterStatus {
    return { ...this._status };
  }

  protected trackOutbound(): void {
    this._status = {
      ...this._status,
      messageCount: {
        ...this._status.messageCount,
        outbound: this._status.messageCount.outbound + 1,
      },
    };
  }

  protected trackInbound(): void {
    this._status = {
      ...this._status,
      messageCount: {
        ...this._status.messageCount,
        inbound: this._status.messageCount.inbound + 1,
      },
    };
  }

  protected recordError(err: unknown): void {
    const message = err instanceof Error ? err.message : String(err);
    this._status = {
      ...this._status,
      state: 'error',
      errorCount: this._status.errorCount + 1,
      lastError: message,
      lastErrorAt: new Date().toISOString(),
    };
  }

  protected abstract _start(relay: RelayPublisher): Promise<void>;
  protected abstract _stop(): Promise<void>;
  abstract deliver(
    subject: string,
    envelope: RelayEnvelope,
    context?: AdapterContext,
  ): Promise<DeliveryResult>;
}
```

