```

Add a `checkApiVersion` function:

```typescript
/**
 * Check adapter API version compatibility and warn on mismatch.
 *
 * - If the adapter declares no apiVersion, skip the check.
 * - If major versions differ, warn about major version mismatch.
 * - If adapter's minor version exceeds host's, warn that adapter expects newer features.
 *
 * Warning-level only — never blocks adapter loading. Modeled on VS Code's
 * `engines.vscode` behavior.
 *
 * @param manifest - The adapter's manifest
 * @param adapterId - The adapter ID for log context
 * @param logger - Logger instance for warnings
 */
function checkApiVersion(
  manifest: AdapterManifest,
  adapterId: string,
  logger: Logger,
): void {
  if (!manifest.apiVersion) return;

  const [hostMajor, hostMinor] = RELAY_ADAPTER_API_VERSION.split('.').map(Number);
  const [adapterMajor, adapterMinor] = manifest.apiVersion.split('.').map(Number);

  if (hostMajor !== adapterMajor) {
    logger.warn(
      `[PluginLoader] Adapter '${adapterId}' targets API v${manifest.apiVersion} ` +
      `but host is v${RELAY_ADAPTER_API_VERSION} (major version mismatch)`,
    );
  } else if (adapterMinor > hostMinor) {
    logger.warn(
      `[PluginLoader] Adapter '${adapterId}' targets API v${manifest.apiVersion} ` +
      `but host is v${RELAY_ADAPTER_API_VERSION} (adapter expects newer features)`,
    );
  }
}
```

